BEGIN TRANSACTION;
  UPDATE accounts SET balance = balance - 100 WHERE id = 1;
  SAVEPOINT after_debit;
  UPDATE accounts SET balance = balance + 100 WHERE id = 99999; -- Invalid ID
  ROLLBACK TO SAVEPOINT after_debit; -- Undo just the second update
COMMIT;

