WITH regional_sales AS (
  SELECT region, SUM(amount) AS total_sales
  FROM orders
  GROUP BY region
)
SELECT * FROM regional_sales WHERE total_sales > 1000000;

-- Break complex query into steps
WITH dept_salaries AS (
  SELECT dept_id, AVG(salary) AS avg_sal
  FROM employee GROUP BY dept_id
), high_earners AS (
  SELECT * FROM employee
  WHERE salary > (SELECT avg_sal FROM dept_salaries WHERE dept_id = employee.dept_id)
)
SELECT * FROM high_earners;

WITH regional_sales AS (
    SELECT region, SUM(amount) AS total_sales
    FROM orders GROUP BY region
), top_regions AS (
    SELECT region FROM regional_sales
    WHERE total_sales > (SELECT SUM(total_sales)/10 FROM regional_sales)
)
SELECT region, product, SUM(quantity) AS product_units
FROM orders WHERE region IN (SELECT region FROM top_regions)
GROUP BY region, product;

CREATE TRIGGER log_salary_change
AFTER UPDATE ON employee
FOR EACH ROW EXECUTE PROCEDURE write_log();

CREATE TRIGGER my_trigger
AFTER INSERT OR UPDATE OR DELETE ON employee
FOR EACH ROW EXECUTE PROCEDURE process_change();

CREATE FUNCTION write_log() RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO change_log (table_name, old_value, new_value)
  VALUES ('employee', OLD.salary, NEW.salary);  -- OLD = before, NEW = after
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE FUNCTION write_log() RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO employee_change_log(employee_id, changedAt, salary)
  VALUES (NEW.employee_id, CURRENT_TIMESTAMP, NEW.salary);
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Complex validation across tables
CREATE FUNCTION check_department_hiring() RETURNS TRIGGER AS $$
BEGIN
  IF (SELECT status FROM department WHERE dept_id = NEW.dept_id) != 'hiring' THEN
    RAISE EXCEPTION 'Department is not hiring';
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Step 1: Create the function first
CREATE FUNCTION write_log() RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO employee_change_log VALUES (NEW.employee_id, CURRENT_TIMESTAMP, NEW.salary);
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

-- Step 2: Then create the trigger that uses it
CREATE TRIGGER log_trigger AFTER UPDATE ON employee
FOR EACH ROW EXECUTE PROCEDURE write_log();

-- Performance index for fast lookup by director
CREATE INDEX director_idx ON films (director);

-- Unique index to prevent duplicate emails
CREATE UNIQUE INDEX ak_email ON users (email);

CREATE INDEX director_idx ON films (director);
-- This index helps queries like:
-- SELECT * FROM films WHERE director = 'Christopher Nolan';

-- Non-unique index: allows multiple films with same rating
CREATE INDEX rating_idx ON films (rating);

-- Unique index: each email can only be used once
CREATE UNIQUE INDEX email_idx ON users (email);

CREATE INDEX idx_student_major_minor ON student (major, minor);
-- Helps queries like:
-- SELECT * FROM student WHERE major = 'CS' AND minor = 'Math';
-- Also helps: WHERE major = 'CS' (uses first column)

CREATE INDEX idx_category_title_rating ON film (category) INCLUDE (title, rating);
-- Query can get title and rating directly from the index:
-- SELECT title, rating FROM film WHERE category = 'Action';
-- No need to access the table itself!

-- This index 'covers' queries that need just these columns
CREATE INDEX idx_covering ON orders (customer_id, order_date) INCLUDE (total_amount);

-- Fully covered - no table lookup needed:
SELECT order_date, total_amount FROM orders WHERE customer_id = 123;

-- In PostgreSQL:
CREATE INDEX idx_year ON invoice (tx_year);
CLUSTER invoice USING idx_year;  -- Physically reorders table by tx_year

-- Non-clustered (regular) index just points to rows:
CREATE INDEX idx_customer ON invoice (customer_id);

-- Step 1: Create the index
CREATE INDEX idx_transaction_year ON invoice (tx_year);

-- Step 2: Cluster (physically reorder) the table using this index
CLUSTER invoice USING idx_transaction_year;

-- Periodically re-cluster as data changes
CLUSTER invoice;

-- Initial clustering
CREATE INDEX idx_year ON sales (sale_year);
CLUSTER sales USING idx_year;

-- Later, after much new data:
CLUSTER sales;  -- Re-apply clustering based on the same index

-- See the query plan
EXPLAIN SELECT * FROM book WHERE publisher_code = 'P001';

-- See plan with actual execution statistics
EXPLAIN ANALYZE SELECT * FROM book WHERE publisher_code = 'P001';

-- Without index on publisher_code:
EXPLAIN SELECT * FROM book WHERE publisher_code = 'P001';
-- Result: 'Seq Scan on book' - checks every row!

-- After creating index:
CREATE INDEX idx_pub ON book (publisher_code);
-- Now uses: 'Index Scan using idx_pub'

-- Each of these indexes helps certain queries but slows writes:
CREATE INDEX idx1 ON orders (customer_id);
CREATE INDEX idx2 ON orders (order_date);
CREATE INDEX idx3 ON orders (status);
CREATE INDEX idx4 ON orders (total_amount);

-- INSERT INTO orders must now update ALL 4 indexes!

-- Cluster by month for monthly reporting queries
CREATE INDEX idx_tx_month ON transactions (tx_year, tx_month);
CLUSTER transactions USING idx_tx_month;

-- Now monthly reports (WHERE tx_year = 2024 AND tx_month = 1)
-- retrieve contiguous blocks of data efficiently

